import React from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight } from 'lucide-react';

function Navbar() {
  const [isOpen, setIsOpen] = React.useState(false);

  return (
    <nav className="bg-zinc-950 text-zinc-100 py-4 md:py-6 lg:py-8">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-lg font-bold">NexaShop</Link>
        <button className="md:hidden" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <ArrowRight className="w-6 h-6" /> : <ArrowRight className="w-6 h-6 rotate-180" />}
        </button>
        <ul className={`md:flex md:items-center ${isOpen ? 'block' : 'hidden'} md:block`}>
          <li className="md:ml-4 lg:ml-6"><Link to="/" className="hover:text-emerald-500 transition duration-200">Home</Link></li>
          <li className="md:ml-4 lg:ml-6"><Link to="/" className="hover:text-emerald-500 transition duration-200">Features</Link></li>
          <li className="md:ml-4 lg:ml-6"><Link to="/" className="hover:text-emerald-500 transition duration-200">Pricing</Link></li>
        </ul>
      </div>
    </nav>
  );
}

export default Navbar;

