import React from 'react';

function BentoFeatures() {
  const [activeFeature, setActiveFeature] = React.useState(0);

  const features = [
    { title: 'Feature 1', description: 'This is feature 1' },
    { title: 'Feature 2', description: 'This is feature 2' },
    { title: 'Feature 3', description: 'This is feature 3' },
  ];

  return (
    <section className="bg-zinc-950 text-zinc-100 py-12 md:py-24 lg:py-36">
      <div className="container mx-auto flex flex-col items-center justify-center">
        <h2 className="text-2xl md:text-4xl lg:text-6xl font-bold mb-4 md:mb-6 lg:mb-8">Features</h2>
        <div className="flex flex-col md:flex-row lg:flex-row items-center justify-center">
          {features.map((feature, index) => (
            <button key={index} className={`bg-zinc-900 hover:bg-zinc-800 text-zinc-100 py-2 md:py-4 lg:py-6 px-4 md:px-6 lg:px-8 rounded-xl shadow-md shadow-zinc-800/50 mb-4 md:mb-0 lg:mb-0 ${activeFeature === index ? 'bg-emerald-500' : ''}`} onClick={() => setActiveFeature(index)}>{feature.title}</button>
          ))}
        </div>
        <p className="text-lg md:text-2xl lg:text-3xl mb-4 md:mb-6 lg:mb-8 text-zinc-300">{features[activeFeature].description}</p>
      </div>
    </section>
  );
}

export default BentoFeatures;

